  1→---
  2→import BaseLayout from "@/layouts/base.astro";
  3→import { getClients, getTestimonials, getPosts, getProjects, getAwards } from "@/lib/collections";
  4→import { cdnUrl } from "@/lib/cdn";
  5→
  6→const clients = await getClients();
  7→const testimonials = await getTestimonials();
  8→const recentPosts = (await getPosts()).slice(0, 4);
  9→const featuredProjects = (await getProjects()).slice(0, 3);
 10→const awards = await getAwards();
 11→
 12→// Rough reading time estimate
 13→function readingTime(_post: (typeof recentPosts)[number]): string {
 14→  // Placeholder — real implementation would use word count from rendered content
 15→  return "5 min read";
 16→}
 17→
 18→// Industries — hardcoded, unlikely to change often
 19→const industries = [
 20→  "Sports and entertainment",
 21→  "Education and Tech",
 22→  "Commerce",
 23→  "Hospitality",
 24→  "Health and wellness",
 25→  "Real Estate and Finance",
 26→];
 27→
 28→// Capabilities — hardcoded
 29→const capabilities = ["Ecommerce", "Websites", "Desktop Apps", "Web Apps", "Watch & TV Apps", "Mobile Apps", "Kiosks"];
 30→---
 31→
 32→<BaseLayout
 33→  title="Significa"
 34→  description="Building apps, websites, and e-commerce platforms that triple revenue, 5x sales, and improve conversions."
 35→>
 36→  <!-- Hero -->
 37→  <section class="hero">
 38→    <div class="hero-inner">
 39→      <h1>
 40→        <span class="hero-muted"
 41→          >Building apps, websites, and e&#8209;commerce platforms that triple revenue, 5x sales, and improve conversions.</span
 42→        >{" "}
 43→        <a href="/work-with-us" class="hero-cta">Work with us</a>
 44→      </h1>
 45→    </div>
 46→  </section>
 47→
 48→  <!-- Highlights / recent articles -->
 49→  {
 50→    recentPosts.length > 0 && (
 51→      <section class="highlights">
 52→        <div class="highlights-inner">
 53→          <ul>
 54→            {recentPosts.map((post, i) => (
 55→              <li class:list={["highlight-item", { first: i === 0 }]}>
 56→                <a href={`/blog/${post.id}`}>
 57→                  <span class="highlight-title">{post.data.title}</span>
 58→                  <span class="highlight-meta">
 59→                    {readingTime(post)}
 60→                    {i === 0 && (
 61→                      <span class="highlight-arrow" aria-hidden="true">
 62→                        →
 63→                      </span>
 64→                    )}
 65→                  </span>
 66→                </a>
 67→              </li>
 68→            ))}
 69→          </ul>
 70→        </div>
 71→      </section>
 72→    )
 73→  }
 74→
 75→  <!-- Showreel -->
 76→  <section class="showreel" data-showreel>
 77→    <div class="showreel-inner">
 78→      <div class="showreel-media">
 79→        <!--
 80→                    Replace with actual showreel thumbnail via CDN:
 81→                    <img src={cdnUrl("showreel/thumbnail.jpg", { width: 1920, quality: 85 })}
 82→                         alt="Significa showreel preview"
 83→                         width="1920" height="1200"
 84→                         loading="eager" decoding="async" />
 85→                -->
 86→        <div class="showreel-placeholder" aria-label="Showreel video"></div>
 87→        <button class="showreel-cursor" type="button" data-showreel-cursor aria-label="Play showreel video">
 88→          <span class="showreel-cursor-icon" aria-hidden="true">▶</span>
 89→          Play showreel
 90→        </button>
 91→      </div>
 92→    </div>
 93→  </section>
 94→
 95→  <!-- Featured projects showcase -->
 96→  {
 97→    featuredProjects.length > 0 && (
 98→      <section class="project-showcase">
 99→        <div class="project-showcase-inner">
100→          {featuredProjects.map((project, i) => (
101→            <article class:list={["showcase-project", { "showcase-project--wide": i === 2 }]}>
102→              <a href={`/projects/${project.id}`}>
103→                <div class="showcase-project-label">{project.data.client ?? project.data.title}</div>
104→                <div class="showcase-project-image">
105→                  <img
106→                    src={cdnUrl(project.data.heroImage ?? project.data.thumbnail, {
107→                      width: i === 2 ? 1280 : 640,
108→                      quality: 80,
109→                    })}
110→                    alt={project.data.title}
111→                    width={i === 2 ? "1280" : "640"}
112→                    height={i === 2 ? "800" : "480"}
113→                    loading="lazy"
114→                    decoding="async"
115→                  />
116→                </div>
117→                {project.data.metrics.length > 0 && (
118→                  <ul class="showcase-project-metrics">
119→                    {project.data.metrics.map((m) => (
120→                      <li class="metric-pill">
121→                        <span class="metric-value">{m.value}</span>
122→                        <span class="metric-label">{m.label}</span>
123→                      </li>
124→                    ))}
125→                  </ul>
126→                )}
127→              </a>
128→            </article>
129→          ))}
130→        </div>
131→      </section>
132→    )
133→  }
134→
135→  <!-- Awards -->
136→  {
137→    awards.length > 0 && (
138→      <section class="awards">
139→        <div class="awards-inner">
140→          <div class="awards-header">
141→            <h2>Ah, awards. Who doesn't like validation?</h2>
142→          </div>
143→          <ul class="awards-list">
144→            {awards.map((a) => (
145→              <li class="award-item">
146→                {a.url ? (
