154→                    <span class="award-name">{a.award}</span>
155→                    <span class="award-year">{a.year}</span>
156→                    <span class="award-project">{a.project?.data.client ?? a.project?.data.title}</span>
157→                  </span>
158→                )}
159→              </li>
160→            ))}
161→          </ul>
162→        </div>
163→      </section>
164→    )
165→  }
166→
167→  <!-- Industries -->
168→  <section class="expertise">
169→    <div class="expertise-inner">
170→      <div class="expertise-block">
171→        <h2>Transforming insights into interfaces people love, across industries.</h2>
172→        <ul class="expertise-list">
173→          {
174→            industries.map((item) => (
175→              <li class="expertise-item">
176→                <span>{item}</span>
177→              </li>
178→            ))
179→          }
180→        </ul>
181→      </div>
182→    </div>
183→  </section>
184→
185→  <!-- Capabilities -->
186→  <section class="expertise">
187→    <div class="expertise-inner">
188→      <div class="expertise-block">
189→        <h2>Writing code that does what it's supposed to, whenever it runs.</h2>
190→        <ul class="expertise-list">
191→          {
192→            capabilities.map((item) => (
193→              <li class="expertise-item">
194→                <span>{item}</span>
195→              </li>
196→            ))
197→          }
198→        </ul>
199→      </div>
200→    </div>
201→  </section>
202→
203→  <!-- Stats + Testimonial -->
204→  <section class="social-proof">
205→    <div class="social-proof-inner">
206→      <div class="stats-card">
207→        <span class="stats-label">Customer experience</span>
208→        <span class="stats-value">84.7%</span>
209→        <p class="stats-description">
210→          Bring your specs to Significa but give them the creative freedom to unleash the best possible design and solution for
211→          your product needs and users.
212→        </p>
213→      </div>
214→
215→      {
216→        testimonials[0] && (
217→          <blockquote class="testimonial-card">
218→            <p class="testimonial-quote">{testimonials[0].data.quote}</p>
219→            <footer class="testimonial-author">
220→              <cite>
221→                <strong>{testimonials[0].data.author}</strong>
222→                <span>
223→                  {testimonials[0].data.role} at {testimonials[0].data.company}
224→                </span>
225→              </cite>
226→            </footer>
227→          </blockquote>
228→        )
229→      }
230→    </div>
231→  </section>
232→
233→  <!-- Client logos -->
234→  {
235→    clients.length > 0 && (
236→      <section class="clients">
237→        <div class="clients-inner">
238→          <ul>
239→            {clients.map((client) => (
240→              <li>
241→                {client.data.url ? (
242→                  <a href={client.data.url} target="_blank" rel="noopener noreferrer" title={client.data.name}>
243→                    <span class="client-name">{client.data.name}</span>
244→                  </a>
245→                ) : (
246→                  <span class="client-name">{client.data.name}</span>
247→                )}
248→              </li>
249→            ))}
250→          </ul>
251→        </div>
252→      </section>
253→    )
254→  }
255→
256→  <!-- Team photo -->
257→  <section class="team-photo">
258→    <div class="team-photo-inner">
259→      <!--
260→                Replace with actual team photo via CDN:
261→                <img src={cdnUrl("team/office.jpg", { width: 1920, quality: 80 })}
262→                     alt="The Significa team collaborating at their Porto studio"
263→                     width="1920" height="1080" loading="lazy" decoding="async" />
264→            -->
265→      <div class="team-photo-placeholder">
266→        <p>Team photo</p>
267→      </div>
268→    </div>
269→  </section>
270→</BaseLayout>
