272→<!-- Showreel cursor-following button — vanilla JS, no island needed -->
273→<script>
274→  function initShowreel() {
275→    const section = document.querySelector<HTMLElement>("[data-showreel]");
276→    const cursor = document.querySelector<HTMLButtonElement>("[data-showreel-cursor]");
277→    if (!section || !cursor) return;
278→
279→    let rafId: number | null = null;
280→    let mouseX = 0;
281→    let mouseY = 0;
282→    let cursorX = 0;
283→    let cursorY = 0;
284→    let isInside = false;
285→
286→    // Lerp factor — lower = smoother trailing
287→    const ease = 0.15;
288→
289→    function animate() {
290→      cursorX += (mouseX - cursorX) * ease;
291→      cursorY += (mouseY - cursorY) * ease;
292→      cursor!.style.transform = `translate(${cursorX}px, ${cursorY}px)`;
293→      rafId = requestAnimationFrame(animate);
294→    }
295→
296→    section.addEventListener("mouseenter", () => {
297→      isInside = true;
298→      cursor.style.opacity = "1";
299→      rafId = requestAnimationFrame(animate);
300→    });
301→
302→    section.addEventListener("mouseleave", () => {
303→      isInside = false;
304→      cursor.style.opacity = "0";
305→      if (rafId !== null) {
306→        cancelAnimationFrame(rafId);
307→        rafId = null;
308→      }
309→    });
310→
311→    section.addEventListener("mousemove", (e: MouseEvent) => {
312→      if (!isInside) return;
313→      const rect = section.getBoundingClientRect();
314→      // Position relative to section center, offset by half cursor size
315→      mouseX = e.clientX - rect.left - cursor.offsetWidth / 2;
316→      mouseY = e.clientY - rect.top - cursor.offsetHeight / 2;
317→    });
318→
319→    // Respect reduced motion
320→    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)");
321→    if (prefersReducedMotion.matches) {
322→      cursor.style.display = "none";
323→    }
324→    prefersReducedMotion.addEventListener("change", (e) => {
325→      cursor.style.display = e.matches ? "none" : "";
326→    });
327→  }
328→
329→  // Run on initial load and after View Transition navigation
330→  initShowreel();
331→  document.addEventListener("astro:after-swap", initShowreel);
332→</script>
