---
import BaseLayout from "@/layouts/base.astro";
import { getClients, getTestimonials, getPosts, getProjects, getAwards } from "@/lib/collections";
import { cdnUrl } from "@/lib/cdn";

const clients = await getClients();
const testimonials = await getTestimonials();
const recentPosts = (await getPosts()).slice(0, 4);
const featuredProjects = (await getProjects()).slice(0, 3);
const awards = await getAwards();

// Rough reading time estimate
function readingTime(_post: (typeof recentPosts)[number]): string {
  // Placeholder — real implementation would use word count from rendered content
  return "5 min read";
}

// Industries — hardcoded, unlikely to change often
const industries = [
  "Sports and entertainment",
  "Education and Tech",
  "Commerce",
  "Hospitality",
  "Health and wellness",
  "Real Estate and Finance",
];

// Capabilities — hardcoded
const capabilities = ["Ecommerce", "Websites", "Desktop Apps", "Web Apps", "Watch & TV Apps", "Mobile Apps", "Kiosks"];
---

<BaseLayout
  title="Significa"
  description="Building apps, websites, and e-commerce platforms that triple revenue, 5x sales, and improve conversions."
>
  <!-- Hero -->
  <section class="hero">
    <div class="hero-inner">
      <h1>
        <span class="hero-muted"
          >Building apps, websites, and e&#8209;commerce platforms that triple revenue, 5x sales, and improve conversions.</span
        >{" "}
        <a href="/work-with-us" class="hero-cta">Work with us</a>
      </h1>
    </div>
  </section>

  <!-- Highlights / recent articles -->
  {
    recentPosts.length > 0 && (
      <section class="highlights">
        <div class="highlights-inner">
          <ul>
            {recentPosts.map((post, i) => (
              <li class:list={["highlight-item", { first: i === 0 }]}>
                <a href={`/blog/${post.id}`}>
                  <span class="highlight-title">{post.data.title}</span>
                  <span class="highlight-meta">
                    {readingTime(post)}
                    {i === 0 && (
                      <span class="highlight-arrow" aria-hidden="true">
                        →
                      </span>
                    )}
                  </span>
                </a>
              </li>
            ))}
          </ul>
        </div>
      </section>
    )
  }

  <!-- Showreel -->
  <section class="showreel" data-showreel>
    <div class="showreel-inner">
      <div class="showreel-media">
        <!--
                    Replace with actual showreel thumbnail via CDN:
                    <img src={cdnUrl("showreel/thumbnail.jpg", { width: 1920, quality: 85 })}
                         alt="Significa showreel preview"
                         width="1920" height="1200"
                         loading="eager" decoding="async" />
                -->
        <div class="showreel-placeholder" aria-label="Showreel video"></div>
        <button class="showreel-cursor" type="button" data-showreel-cursor aria-label="Play showreel video">
          <span class="showreel-cursor-icon" aria-hidden="true">▶</span>
          Play showreel
        </button>
      </div>
    </div>
  </section>

  <!-- Featured projects showcase -->
  {
    featuredProjects.length > 0 && (
      <section class="project-showcase">
        <div class="project-showcase-inner">
          {featuredProjects.map((project, i) => (
            <article class:list={["showcase-project", { "showcase-project--wide": i === 2 }]}>
              <a href={`/projects/${project.id}`}>
                <div class="showcase-project-label">{project.data.client ?? project.data.title}</div>
                <div class="showcase-project-image">
                  <img
                    src={cdnUrl(project.data.heroImage ?? project.data.thumbnail, {
                      width: i === 2 ? 1280 : 640,
                      quality: 80,
                    })}
                    alt={project.data.title}
                    width={i === 2 ? "1280" : "640"}
                    height={i === 2 ? "800" : "480"}
                    loading="lazy"
                    decoding="async"
                  />
                </div>
                {project.data.metrics.length > 0 && (
                  <ul class="showcase-project-metrics">
                    {project.data.metrics.map((m) => (
                      <li class="metric-pill">
                        <span class="metric-value">{m.value}</span>
                        <span class="metric-label">{m.label}</span>
                      </li>
                    ))}
                  </ul>
                )}
              </a>
            </article>
          ))}
        </div>
      </section>
    )
  }

  <!-- Awards -->
  {
    awards.length > 0 && (
      <section class="awards">
        <div class="awards-inner">
          <div class="awards-header">
            <h2>Ah, awards. Who doesn't like validation?</h2>
          </div>
          <ul class="awards-list">
            {awards.map((a) => (
              <li class="award-item">
                {a.url ? (
                  <a href={a.url} target="_blank" rel="noopener noreferrer">
                    <span class="award-name">{a.award}</span>
                    <span class="award-year">{a.year}</span>
                    <span class="award-project">{a.project?.data.client ?? a.project?.data.title}</span>
                  </a>
                ) : (
                  <span class="award-item-inner">
                    <span class="award-name">{a.award}</span>
                    <span class="award-year">{a.year}</span>
                    <span class="award-project">{a.project?.data.client ?? a.project?.data.title}</span>
                  </span>
                )}
              </li>
            ))}
          </ul>
        </div>
      </section>
    )
  }

  <!-- Industries -->
  <section class="expertise">
    <div class="expertise-inner">
      <div class="expertise-block">
        <h2>Transforming insights into interfaces people love, across industries.</h2>
        <ul class="expertise-list">
          {
            industries.map((item) => (
              <li class="expertise-item">
                <span>{item}</span>
              </li>
            ))
          }
        </ul>
      </div>
    </div>
  </section>

  <!-- Capabilities -->
  <section class="expertise">
    <div class="expertise-inner">
      <div class="expertise-block">
        <h2>Writing code that does what it's supposed to, whenever it runs.</h2>
        <ul class="expertise-list">
          {
            capabilities.map((item) => (
              <li class="expertise-item">
                <span>{item}</span>
              </li>
            ))
          }
        </ul>
      </div>
    </div>
  </section>

  <!-- Stats + Testimonial -->
  <section class="social-proof">
    <div class="social-proof-inner">
      <div class="stats-card">
        <span class="stats-label">Customer experience</span>
        <span class="stats-value">84.7%</span>
        <p class="stats-description">
          Bring your specs to Significa but give them the creative freedom to unleash the best possible design and solution for
          your product needs and users.
        </p>
      </div>

      {
        testimonials[0] && (
          <blockquote class="testimonial-card">
            <p class="testimonial-quote">{testimonials[0].data.quote}</p>
            <footer class="testimonial-author">
              <cite>
                <strong>{testimonials[0].data.author}</strong>
                <span>
                  {testimonials[0].data.role} at {testimonials[0].data.company}
                </span>
              </cite>
            </footer>
          </blockquote>
        )
      }
    </div>
  </section>

  <!-- Client logos -->
  {
    clients.length > 0 && (
      <section class="clients">
        <div class="clients-inner">
          <ul>
            {clients.map((client) => (
              <li>
                {client.data.url ? (
                  <a href={client.data.url} target="_blank" rel="noopener noreferrer" title={client.data.name}>
                    <span class="client-name">{client.data.name}</span>
                  </a>
                ) : (
                  <span class="client-name">{client.data.name}</span>
                )}
              </li>
            ))}
          </ul>
        </div>
      </section>
    )
  }

  <!-- Team photo -->
  <section class="team-photo">
    <div class="team-photo-inner">
      <!--
                Replace with actual team photo via CDN:
                <img src={cdnUrl("team/office.jpg", { width: 1920, quality: 80 })}
                     alt="The Significa team collaborating at their Porto studio"
                     width="1920" height="1080" loading="lazy" decoding="async" />
            -->
      <div class="team-photo-placeholder">
        <p>Team photo</p>
      </div>
    </div>
  </section>
</BaseLayout>

<!-- Showreel cursor-following button — vanilla JS, no island needed -->
<script>
  function initShowreel() {
    const section = document.querySelector<HTMLElement>("[data-showreel]");
    const cursor = document.querySelector<HTMLButtonElement>("[data-showreel-cursor]");
    if (!section || !cursor) return;

    let rafId: number | null = null;
    let mouseX = 0;
    let mouseY = 0;
    let cursorX = 0;
    let cursorY = 0;
    let isInside = false;

    // Lerp factor — lower = smoother trailing
    const ease = 0.15;

    function animate() {
      cursorX += (mouseX - cursorX) * ease;
      cursorY += (mouseY - cursorY) * ease;
      cursor!.style.transform = `translate(${cursorX}px, ${cursorY}px)`;
      rafId = requestAnimationFrame(animate);
    }

    section.addEventListener("mouseenter", () => {
      isInside = true;
      cursor.style.opacity = "1";
      rafId = requestAnimationFrame(animate);
    });

    section.addEventListener("mouseleave", () => {
      isInside = false;
      cursor.style.opacity = "0";
      if (rafId !== null) {
        cancelAnimationFrame(rafId);
        rafId = null;
      }
    });

    section.addEventListener("mousemove", (e: MouseEvent) => {
      if (!isInside) return;
      const rect = section.getBoundingClientRect();
      // Position relative to section center, offset by half cursor size
      mouseX = e.clientX - rect.left - cursor.offsetWidth / 2;
      mouseY = e.clientY - rect.top - cursor.offsetHeight / 2;
    });

    // Respect reduced motion
    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)");
    if (prefersReducedMotion.matches) {
      cursor.style.display = "none";
    }
    prefersReducedMotion.addEventListener("change", (e) => {
      cursor.style.display = e.matches ? "none" : "";
    });
  }

  // Run on initial load and after View Transition navigation
  initShowreel();
  document.addEventListener("astro:after-swap", initShowreel);
</script>

<style>
  /* ============================================================
       Hero
       ============================================================ */
  .hero {
    padding: var(--space-32) var(--gutter) var(--space-16);
  }

  .hero-inner {
    max-width: var(--max-width-narrow);
    margin: 0 auto;
  }

  .hero h1 {
    font-size: var(--text-3xl);
    font-weight: var(--weight-normal);
    line-height: var(--leading-tight);
  }

  .hero-muted {
    color: var(--color-text-muted);
  }

  .hero-cta {
    color: var(--color-text);
    text-decoration: underline;
    text-underline-offset: 0.15em;
    text-decoration-thickness: 1px;
  }

  .hero-cta:hover {
    color: var(--color-text);
    text-decoration-thickness: 2px;
  }

  /* ============================================================
       Highlights
       ============================================================ */
  .highlights {
    padding: 0 var(--gutter) var(--space-16);
  }

  .highlights-inner {
    max-width: var(--max-width-narrow);
    margin: 0 auto;
  }

  .highlights ul {
    list-style: none;
    border-top: 1px solid var(--color-border);
  }

  .highlight-item a {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: var(--space-4);
    padding: var(--space-3) 0;
    border-bottom: 1px solid var(--color-border);
    text-decoration: none;
    color: var(--color-text-muted);
    transition: color var(--duration-fast) var(--ease-out);
  }

  .highlight-item a:hover {
    color: var(--color-text);
  }

  .highlight-item.first a {
    color: var(--color-text);
    font-weight: var(--weight-medium);
  }

  .highlight-title {
    font-size: var(--text-base);
  }

  .highlight-meta {
    display: flex;
    align-items: center;
    gap: var(--space-2);
    font-size: var(--text-sm);
    white-space: nowrap;
  }

  .highlight-arrow {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.5rem;
    height: 1.5rem;
    border-radius: 50%;
    border: 1px solid var(--color-border);
    font-size: 0.75rem;
  }

  /* ============================================================
       Showreel
       ============================================================ */
  .showreel {
    padding: 0 var(--gutter) var(--space-16);
  }

  .showreel-inner {
    max-width: var(--max-width);
    margin: 0 auto;
  }

  .showreel-media {
    position: relative;
    border-radius: var(--space-2);
    overflow: hidden;
    cursor: none;
  }

  .showreel-placeholder {
    aspect-ratio: 16 / 10;
    background-color: var(--color-surface-alt);
  }

  .showreel-cursor {
    position: absolute;
    top: 0;
    left: 0;
    z-index: 1;
    display: inline-flex;
    align-items: center;
    gap: var(--space-2);
    padding: var(--space-3) var(--space-6);
    background: var(--color-text);
    color: var(--color-surface);
    border: none;
    border-radius: 2rem;
    font-size: var(--text-sm);
    font-weight: var(--weight-medium);
    pointer-events: none;
    opacity: 0;
    transition: opacity var(--duration-fast) var(--ease-out);
    will-change: transform;
    white-space: nowrap;
  }

  .showreel-cursor-icon {
    font-size: 0.625rem;
  }

  /* Fallback: on touch devices, show a static centered button */
  @media (hover: none) {
    .showreel-media {
      cursor: default;
    }

    .showreel-cursor {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%) !important;
      opacity: 1 !important;
      pointer-events: auto;
    }
  }

  /* ============================================================
       Project showcase
       ============================================================ */
  .project-showcase {
    padding: 0 var(--gutter) var(--space-16);
  }

  .project-showcase-inner {
    max-width: var(--max-width);
    margin: 0 auto;
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: var(--space-4);
  }

  .showcase-project a {
    display: block;
    text-decoration: none;
    color: var(--color-text);
  }

  .showcase-project--wide {
    grid-column: 1 / -1;
  }

  .showcase-project-label {
    font-size: var(--text-sm);
    font-weight: var(--weight-medium);
    padding: var(--space-3) 0;
  }

  .showcase-project-image {
    border-radius: var(--space-2);
    overflow: hidden;
    background: var(--color-surface-alt);
  }

  .showcase-project-image img {
    width: 100%;
    height: auto;
    display: block;
    transition: transform var(--duration-slow) var(--ease-out);
  }

  .showcase-project a:hover .showcase-project-image img {
    transform: scale(1.02);
  }

  .showcase-project-metrics {
    display: flex;
    gap: var(--space-3);
    list-style: none;
    padding: var(--space-4) 0;
    flex-wrap: wrap;
  }

  .metric-pill {
    display: flex;
    align-items: baseline;
    gap: var(--space-2);
  }

  .metric-value {
    font-size: var(--text-lg);
    font-weight: var(--weight-bold);
    line-height: 1;
  }

  .metric-label {
    font-size: var(--text-sm);
    color: var(--color-text-muted);
  }

  @media (max-width: 640px) {
    .project-showcase-inner {
      grid-template-columns: 1fr;
    }

    .showcase-project--wide {
      grid-column: auto;
    }
  }

  /* ============================================================
       Awards
       ============================================================ */
  .awards {
    padding: var(--space-16) var(--gutter);
  }

  .awards-inner {
    max-width: var(--max-width);
    margin: 0 auto;
    display: grid;
    grid-template-columns: 1fr 2fr;
    gap: var(--space-16);
  }

  .awards-header h2 {
    font-size: var(--text-xl);
    font-weight: var(--weight-bold);
    line-height: var(--leading-tight);
    max-width: 18ch;
    position: sticky;
    top: var(--space-8);
  }

  .awards-list {
    list-style: none;
  }

  .award-item {
    border-bottom: 1px solid var(--color-border);
  }

  .award-item:first-child {
    border-top: 1px solid var(--color-border);
  }

  .award-item a,
  .award-item-inner {
    display: grid;
    grid-template-columns: 1fr auto auto;
    gap: var(--space-4);
    align-items: center;
    padding: var(--space-3) 0;
    text-decoration: none;
    color: var(--color-text);
    transition: opacity var(--duration-fast) var(--ease-out);
  }

  .award-item a:hover {
    opacity: 0.6;
    color: var(--color-text);
  }

  .award-name {
    font-size: var(--text-base);
    font-weight: var(--weight-medium);
  }

  .award-year {
    font-size: var(--text-sm);
    color: var(--color-text-muted);
  }

  .award-project {
    font-size: var(--text-sm);
    color: var(--color-text-muted);
    text-align: right;
  }

  @media (max-width: 768px) {
    .awards-inner {
      grid-template-columns: 1fr;
      gap: var(--space-8);
    }

    .awards-header h2 {
      position: static;
    }

    .award-item a,
    .award-item-inner {
      grid-template-columns: 1fr auto;
    }

    .award-project {
      grid-column: 1 / -1;
    }
  }

  /* ============================================================
       Expertise (industries + capabilities)
       ============================================================ */
  .expertise {
    padding: 0 var(--gutter) var(--space-16);
  }

  .expertise-inner {
    max-width: var(--max-width);
    margin: 0 auto;
  }

  .expertise-block {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: var(--space-16);
  }

  .expertise-block h2 {
    font-size: var(--text-2xl);
    font-weight: var(--weight-bold);
    line-height: var(--leading-tight);
    max-width: 20ch;
  }

  .expertise-list {
    list-style: none;
  }

  .expertise-item {
    padding: var(--space-3) 0;
    border-bottom: 1px solid var(--color-border);
    font-size: var(--text-base);
    color: var(--color-text-muted);
    transition: color var(--duration-fast) var(--ease-out);
  }

  .expertise-item:first-child {
    border-top: 1px solid var(--color-border);
  }

  .expertise-item:hover {
    color: var(--color-text);
  }

  @media (max-width: 768px) {
    .expertise-block {
      grid-template-columns: 1fr;
      gap: var(--space-8);
    }
  }

  /* ============================================================
       Social proof (stats + testimonial)
       ============================================================ */
  .social-proof {
    padding: 0 var(--gutter) var(--space-16);
  }

  .social-proof-inner {
    display: grid;
    grid-template-columns: 3fr 2fr;
    gap: var(--space-4);
    max-width: var(--max-width);
    margin: 0 auto;
  }

  .stats-card {
    background: var(--color-surface-alt);
    padding: var(--space-8);
    border-radius: var(--space-2);
  }

  .stats-label {
    display: block;
    font-size: var(--text-sm);
    color: var(--color-text-muted);
    margin-bottom: var(--space-4);
  }

  .stats-value {
    display: block;
    font-size: clamp(3rem, 2rem + 4vw, 5rem);
    font-weight: var(--weight-bold);
    line-height: 1;
    margin-bottom: var(--space-6);
  }

  .stats-description {
    font-size: var(--text-sm);
    color: var(--color-text-muted);
    max-width: 28ch;
    line-height: var(--leading-normal);
  }

  .testimonial-card {
    background: var(--color-surface-alt);
    padding: var(--space-8);
    border-radius: var(--space-2);
    display: flex;
    flex-direction: column;
    justify-content: space-between;
  }

  .testimonial-quote {
    font-size: var(--text-lg);
    line-height: var(--leading-normal);
    margin-bottom: var(--space-8);
  }

  .testimonial-author cite {
    font-style: normal;
    display: flex;
    flex-direction: column;
    gap: var(--space-1);
  }

  .testimonial-author strong {
    font-size: var(--text-base);
    font-weight: var(--weight-medium);
  }

  .testimonial-author span {
    font-size: var(--text-sm);
    color: var(--color-text-muted);
  }

  @media (max-width: 768px) {
    .social-proof-inner {
      grid-template-columns: 1fr;
    }
  }

  /* ============================================================
       Clients
       ============================================================ */
  .clients {
    padding: 0 var(--gutter) var(--space-16);
  }

  .clients-inner {
    max-width: var(--max-width);
    margin: 0 auto;
  }

  .clients ul {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    justify-content: center;
    gap: var(--space-8);
    list-style: none;
  }

  .clients li a {
    color: var(--color-text);
    text-decoration: none;
    opacity: 0.7;
    transition: opacity var(--duration-fast) var(--ease-out);
  }

  .clients li a:hover {
    opacity: 1;
    color: var(--color-text);
  }

  .client-name {
    font-size: var(--text-sm);
    font-weight: var(--weight-semibold);
    white-space: nowrap;
  }

  /* ============================================================
       Team photo
       ============================================================ */
  .team-photo {
    padding: 0 var(--gutter) var(--space-16);
  }

  .team-photo-inner {
    max-width: var(--max-width);
    margin: 0 auto;
  }

  .team-photo-placeholder {
    aspect-ratio: 16 / 9;
    background: var(--color-surface-alt);
    border-radius: var(--space-2);
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--color-text-muted);
    font-size: var(--text-sm);
  }
</style>

